import{_ as t,o as d,c as o,ag as i}from"./chunks/framework.HG0H2VLS.js";const h=JSON.parse('{"title":"FilterDropdownItem — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/FilterDropdownItem/FilterDropdownItem.figma-notes.md","filePath":"public/demos/src/components/FilterDropdownItem/FilterDropdownItem.figma-notes.md"}'),a={name:"public/demos/src/components/FilterDropdownItem/FilterDropdownItem.figma-notes.md"};function r(c,e,n,s,l,p){return d(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="filterdropdownitem-—-figma-notes" tabindex="-1">FilterDropdownItem — Figma Notes <a class="header-anchor" href="#filterdropdownitem-—-figma-notes" aria-label="Permalink to &quot;FilterDropdownItem — Figma Notes&quot;">​</a></h1><h2 id="figma-node" tabindex="-1">Figma Node <a class="header-anchor" href="#figma-node" aria-label="Permalink to &quot;Figma Node&quot;">​</a></h2><ul><li>File: <code>Lus07xi8pPXLN87sQIyrEt</code> (Affino AI Design System)</li><li>Component set: <code>3032:18152</code> — &quot;FilterDropdownItem&quot; — <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=3032-18152" target="_blank" rel="noreferrer">open in Figma</a></li><li>Tier: <code>Component</code> → built into <code>src/components/FilterDropdownItem/</code></li></ul><p>A selectable filter option row: title (&quot;Option name&quot;) + optional sub text, with a green check-circle shown on the right when selected. Designed for a multi-select filter dropdown / listbox.</p><h2 id="variant-×-state-matrix-4-type-×-state" tabindex="-1">Variant × State Matrix (4 = Type × State) <a class="header-anchor" href="#variant-×-state-matrix-4-type-×-state" aria-label="Permalink to &quot;Variant × State Matrix (4 = Type × State)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node ID</th><th>Type</th><th>State</th><th>bg</th><th>Check</th><th>Built</th></tr></thead><tbody><tr><td>3032:18151</td><td>Initial</td><td>Default</td><td>transparent</td><td>hidden</td><td>✅</td></tr><tr><td>3032:18148</td><td>Initial</td><td>Hover</td><td><code>--ai-surface-minimal</code></td><td>hidden</td><td>✅</td></tr><tr><td>3032:18150</td><td>Selected</td><td>Default</td><td>transparent</td><td>visible</td><td>✅</td></tr><tr><td>3032:18149</td><td>Selected</td><td>Hover</td><td><code>--ai-surface-minimal</code></td><td>visible</td><td>✅</td></tr></tbody></table><p><strong>Axis independence (verified):</strong> <code>Type</code> only toggles the check&#39;s <em>visibility</em> — the CircleCheck icon is present in every variant&#39;s layer tree (confirmed in the Initial variant&#39;s design context) and merely hidden when Initial. <code>State=Hover</code> only adds the <code>--ai-surface-minimal</code> background (confirmed on both Selected/Hover and — same fill — via the shared token). CSS represents the cross-product with one <code>--selected</code> modifier</p><ul><li>the <code>:hover</code> pseudo-class rather than 4 rules.</li></ul><h2 id="interaction-confirmed-with-user-2026-07-07" tabindex="-1">Interaction (confirmed with user, 2026-07-07) <a class="header-anchor" href="#interaction-confirmed-with-user-2026-07-07" aria-label="Permalink to &quot;Interaction (confirmed with user, 2026-07-07)&quot;">​</a></h2><ul><li><strong>Multi-select toggle:</strong> clicking an item toggles its own <code>--selected</code> (check on/off) independently — several items can be selected at once. No sibling clearing.</li><li>Built as <code>&lt;button aria-pressed&gt;</code>; <code>FilterDropdownItem.js</code> auto-inits <code>[data-filter-dropdown-item]</code>, toggles <code>.filter-dropdown-item--selected</code> + <code>aria-pressed</code>, and emits a <code>filter-dropdown-item:toggle</code> event <code>{ selected }</code> for the consuming dropdown.</li><li>Hover / focus-visible are pure CSS.</li></ul><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th></tr></thead><tbody><tr><td>Row container</td><td><code>.filter-dropdown-item</code> (<code>&lt;button&gt;</code>, fills container; Figma frame = 280px)</td></tr><tr><td>Selected (Type)</td><td><code>.filter-dropdown-item--selected</code> (reveals the check)</td></tr><tr><td>Hover (State)</td><td><code>:hover</code> → <code>--ai-surface-minimal</code></td></tr><tr><td>Text block</td><td><code>.filter-dropdown-item__text</code></td></tr><tr><td>Title</td><td><code>.filter-dropdown-item__name</code></td></tr><tr><td>Sub text (optional, <code>showSubText</code>)</td><td><code>.filter-dropdown-item__sub</code></td></tr><tr><td>Check icon</td><td><code>.filter-dropdown-item__check</code> (Lucide <code>circle-check</code>, <code>visibility: hidden</code> until <code>--selected</code>)</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Figma variable</th><th>CSS variable</th></tr></thead><tbody><tr><td>Row gap / padding-x</td><td><code>--ai-spacing-3</code> (8px)</td><td><code>--ai-spacing-3</code></td></tr><tr><td>Row padding-y</td><td><code>--ai-spacing-2</code> (6px)</td><td><code>--ai-spacing-2</code></td></tr><tr><td>Row radius</td><td><code>--ai-spacing-3</code> (8px) <em>(see gap)</em></td><td><code>--ai-radius-md</code> (8px)</td></tr><tr><td>Hover bg</td><td><code>--ai-surface-minimal</code></td><td><code>--ai-surface-minimal</code></td></tr><tr><td>Title</td><td><code>--ai-font-body</code> medium, <code>--ai-font-fixed-xs</code> (14px), <code>--ai-leading-sm</code> (20px)</td><td>same</td></tr><tr><td>Title colour</td><td><code>--ai-text-primary</code></td><td><code>--ai-text-primary</code></td></tr><tr><td>Sub text</td><td><code>--ai-font-body</code> regular, <code>--ai-font-fixed-xxs</code> (12px)</td><td>same</td></tr><tr><td>Sub text colour</td><td><code>--ai-text-secondary</code></td><td><code>--ai-text-secondary</code></td></tr><tr><td>Check size</td><td>16px</td><td><code>--ai-icon-size-sm</code></td></tr><tr><td>Check colour</td><td><code>--ai-surface-success</code> (#059669)</td><td><code>--ai-surface-success</code></td></tr></tbody></table><h2 id="token-gaps-decisions" tabindex="-1">Token Gaps / Decisions <a class="header-anchor" href="#token-gaps-decisions" aria-label="Permalink to &quot;Token Gaps / Decisions&quot;">​</a></h2><ul><li><strong>No token gaps</strong> — every value maps to an existing <code>--ai-*</code> token.</li><li><strong>Radius binding quirk:</strong> Figma bound the row <code>border-radius</code> to <code>--ai-spacing-3</code> (a <em>spacing</em> token, 8px). Used <code>--ai-radius-md</code> instead — identical value (8px) and the correct semantic category for a radius. Flagged to the user; no visual difference.</li></ul><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><strong>Icon (Lucide):</strong> Figma layer <code>Icon/24px/CircleCheck</code> → Lucide <code>circle-check</code>. It renders at 16px (<code>--ai-icon-size-sm</code>) despite the 24px component name (base component size, not placed size).</li><li><strong>Check colour</strong> uses <code>--ai-surface-success</code> (a surface token) exactly as Figma bound it — there is no dedicated <code>--ai-icon-success</code> token.</li><li><strong>Width:</strong> the Figma frame is 280px, but the item is built <code>width: 100%</code> to fill whatever dropdown / listbox contains it (280px is the artboard width, not a fixed component size).</li><li><strong>Footer/selected reveal:</strong> the check occupies reserved 16px space even when hidden (<code>visibility: hidden</code>), so Initial and Selected rows share identical layout.</li></ul>',18)])])}const u=t(a,[["render",r]]);export{h as __pageData,u as default};
